import { useState } from 'react';
import { Box, Stepper, Step, StepLabel, Button, Container } from '@mui/material';
import PhotoBookFormatSelector from './PhotoBookFormatSelector';
import PhotoUploader from './PhotoUploader';
import PhotoBookPages from './PhotoBookPages';
import PhotoBookPreview from './PhotoBookPreview';

const steps = [
    'Выберите формат',
    'Загрузите фотографии',
    'Создайте страницы',
    'Предпросмотр'
];

const PhotoBookCreator = () => {
    const [activeStep, setActiveStep] = useState(0);
    const [selectedFormat, setSelectedFormat] = useState(null);
    const [uploadedPhotos, setUploadedPhotos] = useState([]);
    const [pages, setPages] = useState([{ photos: [] }]); // Начинаем с одной пустой страницы

    const handleNext = () => {
        setActiveStep((prevActiveStep) => prevActiveStep + 1);
    };

    const handleBack = () => {
        setActiveStep((prevActiveStep) => prevActiveStep - 1);
    };

    const handleFormatSelect = (format) => {
        setSelectedFormat(format);
    };

    const handlePhotosUpload = (photos) => {
        setUploadedPhotos(photos);
    };

    const handlePagesUpdate = (updatedPages) => {
        setPages(updatedPages);
    };

    const getStepContent = (step) => {
        switch (step) {
            case 0:
                return (
                    <PhotoBookFormatSelector
                        onFormatSelect={handleFormatSelect}
                        selectedFormat={selectedFormat}
                    />
                );
            case 1:
                return (
                    <PhotoUploader
                        onPhotosChange={handlePhotosUpload}
                        photos={uploadedPhotos}
                    />
                );
            case 2:
                return (
                    <PhotoBookPages
                        format={selectedFormat}
                        availablePhotos={uploadedPhotos.map(photo => ({
                            id: photo.id,
                            url: photo.preview,
                            file: photo.file
                        }))}
                        pages={pages}
                        onPagesChange={handlePagesUpdate}
                    />
                );
            case 3:
                return (
                    <PhotoBookPreview
                        format={selectedFormat}
                        pages={pages}
                    />
                );
            default:
                return 'Unknown step';
        }
    };

    const isStepComplete = (step) => {
        switch (step) {
            case 0:
                return !!selectedFormat;
            case 1:
                return uploadedPhotos.length > 0;
            case 2:
                return pages.some(page => page.photos.length > 0);
            case 3:
                return true; // Предпросмотр всегда можно завершить
            default:
                return false;
        }
    };

    return (
        <Container maxWidth="lg">
            <Box sx={{ width: '100%', mt: 4 }}>
                <Stepper activeStep={activeStep}>
                    {steps.map((label, index) => {
                        return (
                            <Step key={label} completed={isStepComplete(index)}>
                                <StepLabel>{label}</StepLabel>
                            </Step>
                        );
                    })}
                </Stepper>

                <Box sx={{ mt: 4, mb: 4 }}>
                    {getStepContent(activeStep)}
                </Box>

                <Box sx={{ display: 'flex', flexDirection: 'row', pt: 2 }}>
                    <Button
                        color="inherit"
                        disabled={activeStep === 0}
                        onClick={handleBack}
                        sx={{ mr: 1 }}
                    >
                        Назад
                    </Button>
                    <Box sx={{ flex: '1 1 auto' }} />
                    <Button
                        onClick={handleNext}
                        disabled={!isStepComplete(activeStep)}
                        variant="contained"
                    >
                        {activeStep === steps.length - 1 ? 'Завершить' : 'Далее'}
                    </Button>
                </Box>
            </Box>
        </Container>
    );
};

export default PhotoBookCreator;
